export const Configuration = () => {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<'general' | 'beds' | 'catalogs' | 'users' | 'data' | 'financial' | 'diagnostics'>('general');
  const [loading, setLoading] = useState(true);

  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');

  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    action: () => void;
    type?: 'danger' | 'warning';
  }>({ isOpen: false, title: '', message: '', action: () => {} });

  // Data States
  const [settings, setSettings] = useState({ hospitalName: '', hospitalAddress: '', hospitalPhone: '', currency: '$' });
  const [healthData, setHealthData] = useState<any>(null);
  const [testLogs, setTestLogs] = useState<string[]>([]);
  const [isTesting, setIsTesting] = useState(false);
  const [users, setUsers] = useState<any[]>([]);
  const [rolePermissions, setRolePermissions] = useState<Record<string, string[]>>({});
  const [beds, setBeds] = useState<BedType[]>([]);
  const [departments, setDepartments] = useState<any[]>([]);
  const [specializations, setSpecializations] = useState<any[]>([]);
  const [labTests, setLabTests] = useState<LabTestCatalog[]>([]);
  const [nurseServices, setNurseServices] = useState<NurseServiceCatalog[]>([]);
  const [operations, setOperations] = useState<OperationCatalog[]>([]);
  const [insuranceProviders, setInsuranceProviders] = useState<InsuranceProvider[]>([]);
  const [banks, setBanks] = useState<any[]>([]);
  const [taxes, setTaxes] = useState<TaxRate[]>([]);
  const [paymentMethods, setPaymentMethods] = useState<PaymentMethod[]>([]);
  const [restoreFile, setRestoreFile] = useState<File | null>(null);

  // Modal & Form States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [userForm, setUserForm] = useState<any>({});
  const [editingUserId, setEditingUserId] = useState<number | null>(null);
  const [userTabMode, setUserTabMode] = useState<'accounts' | 'roles'>('accounts');
  const [availableRoles] = useState<string[]>(['admin', 'manager', 'receptionist', 'technician', 'accountant', 'doctor', 'nurse', 'pharmacist', 'hr']);
  const [isBedModalOpen, setIsBedModalOpen] = useState(false);
  const [bedForm, setBedForm] = useState<Partial<BedType>>({});
  const [editingBedId, setEditingBedId] = useState<number | null>(null);
  const [catalogTab, setCatalogTab] = useState<CatalogType>('lab');
  const [isItemModalOpen, setIsItemModalOpen] = useState(false);
  const [itemFormData, setItemFormData] = useState<any>({});
  const [editingItemId, setEditingItemId] = useState<number | null>(null);
  const [financeForm, setFinanceForm] = useState<any>({});
  const [editingFinanceId, setEditingFinanceId] = useState<number | null>(null);
  const [financeTab, setFinanceTab] = useState<'tax' | 'payment'>('tax');
  const [isFinanceModalOpen, setIsFinanceModalOpen] = useState(false);


  const loadAllData = async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const [s, d, sp, b, l, n, o, ip, bn, u, t, p, rPerms] = await Promise.all([
        api.getSystemSettings(),
        api.getDepartments(),
        api.getSpecializations(),
        api.getConfigBeds(),
        api.getLabTests(),
        api.getNurseServices(),
        api.getOperations(),
        api.getInsuranceProviders(),
        api.getBanks(),
        api.getSystemUsers(),
        api.getTaxRates(),
        api.getPaymentMethods(),
        api.getRolePermissions()
      ]);
      if (s) setSettings(s);
      setDepartments(Array.isArray(d) ? d : []);
      setSpecializations(Array.isArray(sp) ? sp : []);
      setBeds(Array.isArray(b) ? b : []);
      setLabTests(Array.isArray(l) ? l : []);
      setNurseServices(Array.isArray(n) ? n : []);
      setOperations(Array.isArray(o) ? o : []);
      setInsuranceProviders(Array.isArray(ip) ? ip : []);
      setBanks(Array.isArray(bn) ? bn : []);
      setUsers(Array.isArray(u) ? u : []);
      setTaxes(Array.isArray(t) ? t : []);
      setPaymentMethods(Array.isArray(p) ? p : []);
      setRolePermissions(rPerms || {});
    } catch (e) {
      console.error("Failed to load config data", e);
    } finally {
      if (!silent) setLoading(false);
    }
  };

  useEffect(() => { loadAllData(); }, []);

  const handleAction = async (action: () => Promise<void>, successMsg: string) => {
    setProcessStatus('processing');
    setProcessMessage(t('processing'));
    try {
      await action();
      setProcessStatus('success');
      setProcessMessage(successMsg);
      await loadAllData(true);
      setTimeout(() => { setProcessStatus('idle'); }, 1500);
    } catch (e: any) {
      setProcessStatus('error');
      setProcessMessage(e.response?.data?.error || e.message || 'An error occurred');
    }
  };

  // --- Handlers for each section ---

  const handleSaveSettings = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      await api.updateSystemSettings(settings);
      if (settings.hospitalName) localStorage.setItem('hospital_name', settings.hospitalName);
    }, 'Settings saved successfully');
  };

  // User Handlers
  const openUserModal = (user?: any) => {
    setEditingUserId(user ? user.id : null);
    setUserForm(user ? { ...user, password: '' } : { username: '', fullName: '', role: 'manager', isActive: true });
    setIsUserModalOpen(true);
  };
  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (editingUserId) await api.updateSystemUser(editingUserId, userForm);
      else await api.addSystemUser(userForm);
      setIsUserModalOpen(false);
    }, editingUserId ? 'User updated' : 'User created');
  };
  const handleDeleteUser = (id: number) => {
    setConfirmState({
      isOpen: true, title: 'Delete User', message: 'Are you sure? This will remove the user permanently.',
      action: () => handleAction(async () => await api.deleteSystemUser(id), 'User deleted')
    });
  };
  const togglePermission = (role: string, permission: string) => {
    if (role === 'admin') return;
    const currentPerms = rolePermissions[role] || [];
    const updatedPerms = currentPerms.includes(permission) ? currentPerms.filter(p => p !== permission) : [...currentPerms, permission];
    setRolePermissions(prev => ({ ...prev, [role]: updatedPerms }));
  };
  const savePermissions = (role: string) => {
    handleAction(async () => await api.updateRolePermissions(role, rolePermissions[role] || []), `Permissions updated for ${role}`);
  };

  // Bed Handlers
  const openBedModal = (bed?: BedType) => {
    setEditingBedId(bed ? bed.id : null);
    setBedForm(bed ? { ...bed } : { type: 'General', status: 'available', costPerDay: 0 });
    setIsBedModalOpen(true);
  };
  const handleBedSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (editingBedId) await api.updateBed(editingBedId, bedForm);
      else await api.addBed(bedForm);
      setIsBedModalOpen(false);
    }, editingBedId ? 'Room updated' : 'Room added');
  };
  const handleDeleteBed = (id: number) => {
    setConfirmState({
      isOpen: true, title: 'Delete Room', message: 'Are you sure?',
      action: () => handleAction(async () => await api.deleteBed(id), 'Room deleted')
    });
  };

  // Catalog Handlers
  const openItemModal = (item?: any) => {
    setEditingItemId(item ? item.id : null);
    setItemFormData(item ? { ...item } : {});
    setIsItemModalOpen(true);
  };
  const handleItemSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const { apiAdd, apiUpdate } = catalogMetadata[catalogTab];
    handleAction(async () => {
      if (editingItemId) await apiUpdate(editingItemId, itemFormData);
      else await apiAdd(itemFormData);
      setIsItemModalOpen(false);
    }, editingItemId ? 'Item updated' : 'Item added');
  };
  const handleDeleteItem = (id: number) => {
    const { apiDelete } = catalogMetadata[catalogTab];
    setConfirmState({
      isOpen: true, title: 'Delete Item', message: 'This will be permanently removed.',
      action: () => handleAction(async () => await apiDelete(id), 'Item deleted')
    });
  };

  // Financial Handlers
  const openFinanceModal = (type: 'tax' | 'payment', item?: any) => {
    setFinanceTab(type);
    setEditingFinanceId(item ? item.id : null);
    setFinanceForm(item ? { ...item } : { name_en: '', name_ar: '', isActive: true });
    setIsFinanceModalOpen(true);
  };
  const handleFinanceSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleAction(async () => {
      if (financeTab === 'tax') {
        if (editingFinanceId) await api.updateTaxRate(editingFinanceId, financeForm);
        else await api.addTaxRate(financeForm);
      } else {
        if (editingFinanceId) await api.updatePaymentMethod(editingFinanceId, financeForm);
        else await api.addPaymentMethod(financeForm);
      }
      setIsFinanceModalOpen(false);
    }, editingFinanceId ? 'Updated' : 'Created');
  };
  const handleDeleteFinance = (id: number, type: 'tax' | 'payment') => {
    setConfirmState({
      isOpen: true, title: 'Delete Item', message: 'Are you sure?',
      action: () => handleAction(async () => {
        if (type === 'tax') await api.deleteTaxRate(id);
        else await api.deletePaymentMethod(id);
      }, 'Deleted')
    });
  };

  // Data Management Handlers
  const handleDownloadBackup = () => api.downloadBackup();
  const handleRestoreDatabase = (e: React.FormEvent) => {
    e.preventDefault();
    if (!restoreFile) return;
    setConfirmState({
      isOpen: true, title: 'Overwrite Database', message: 'This will completely OVERWRITE the current database. All recent data will be lost. Are you sure?', type: 'danger',
      action: () => handleAction(async () => {
        await api.restoreDatabase(restoreFile);
        setTimeout(() => window.location.reload(), 1500);
      }, 'Database restored. Reloading...')
    });
  };
  const handleResetDatabase = () => {
    setConfirmState({
      isOpen: true, title: 'Factory Reset', message: 'DANGER: This will wipe ALL data and reset the system to its initial state. This action CANNOT be undone.', type: 'danger',
      action: () => handleAction(async () => {
          await api.resetDatabase();
          setTimeout(() => window.location.reload(), 2000);
      }, 'Database reset. Reloading...')
    });
  };

  // Diagnostics
  const runDiagnostics = async () => {
    setIsTesting(true);
    setTestLogs(['Starting diagnostics...']);
    try {
      const addLog = (msg: string) => setTestLogs(prev => [...prev, msg]);
      await new Promise(res => setTimeout(res, 300));

      addLog('Checking API server connectivity...');
      const health = await api.checkSystemHealth();
      setHealthData(health);
      addLog(`✅ Server operational. Uptime: ${(health.uptime / 60).toFixed(1)} mins.`);

      await new Promise(res => setTimeout(res, 500));
      addLog('Verifying database connection...');
      addLog(`✅ Database connected. Latency: ${health.database.latency}.`);

      await new Promise(res => setTimeout(res, 300));
      addLog('All tests passed.');
    } catch (e: any) {
      setTestLogs(prev => [...prev, `❌ Test failed: ${e.message}`]);
      setHealthData({ status: 'error' });
    } finally {
      setIsTesting(false);
    }
  };

  // --- DYNAMIC CATALOG CONFIGURATION ---
  const catalogMetadata: Record<CatalogType, any> = {
    dept: {
      label: 'Departments',
      data: departments,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'description_en', label: 'Description (EN)', type: 'textarea' },
        { name: 'description_ar', label: 'Description (AR)', type: 'textarea' },
      ],
      apiAdd: api.addDepartment, apiUpdate: api.updateDepartment, apiDelete: api.deleteDepartment
    },
    spec: {
      label: 'Specializations',
      data: specializations,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'related_role', label: 'Related Role', type: 'select', options: availableRoles },
        { name: 'description_en', label: 'Description (EN)', type: 'textarea' },
        { name: 'description_ar', label: 'Description (AR)', type: 'textarea' },
      ],
      apiAdd: api.addSpecialization, apiUpdate: api.updateSpecialization, apiDelete: api.deleteSpecialization
    },
    lab: {
      label: 'Lab Tests',
      data: labTests,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'category_en', label: 'Category (EN)', type: 'text' },
        { name: 'category_ar', label: 'Category (AR)', type: 'text' },
        { name: 'cost', label: 'Cost', type: 'number', prefix: '$' },
        { name: 'normal_range', label: 'Normal Range', type: 'text' },
      ],
      apiAdd: api.addLabTest, apiUpdate: api.updateLabTest, apiDelete: api.deleteLabTest
    },
    nurse: {
      label: 'Nurse Services',
      data: nurseServices,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'description_en', label: 'Description (EN)', type: 'textarea' },
        { name: 'description_ar', label: 'Description (AR)', type: 'textarea' },
        { name: 'cost', label: 'Cost', type: 'number', prefix: '$' },
      ],
      apiAdd: api.addNurseService, apiUpdate: api.updateNurseService, apiDelete: api.deleteNurseService
    },
    ops: {
      label: 'Operations',
      data: operations,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'base_cost', label: 'Base Cost', type: 'number', prefix: '$' },
      ],
      apiAdd: api.addOperationCatalog, apiUpdate: api.updateOperationCatalog, apiDelete: api.deleteOperationCatalog
    },
    insurance: {
      label: 'Insurance',
      data: insuranceProviders,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'is_active', label: 'Status', type: 'toggle' },
      ],
      apiAdd: api.addInsuranceProvider, apiUpdate: api.updateInsuranceProvider, apiDelete: api.deleteInsuranceProvider
    },
    banks: {
      label: 'Banks',
      data: banks,
      fields: [
        { name: 'name_en', label: 'Name (EN)', type: 'text', required: true },
        { name: 'name_ar', label: 'Name (AR)', type: 'text', required: true },
        { name: 'is_active', label: 'Status', type: 'toggle' },
      ],
      apiAdd: api.addBank, apiUpdate: api.updateBank, apiDelete: api.deleteBank
    }
  };

  const formatPermissionName = (p: string) => {
    return p.replace(/_/g, ' ').toLowerCase();
  };


  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('config_title')}</h1>

      <div className="flex border-b border-gray-200 dark:border-slate-700 bg-white dark:bg-slate-800 rounded-t-xl px-4 pt-2 overflow-x-auto">
        {[
          { id: 'general', icon: SettingsIcon, label: t('config_tab_general') },
          { id: 'users', icon: Shield, label: t('config_tab_roles') }, 
          { id: 'financial', icon: CreditCard, label: t('config_tab_financial') },
          { id: 'beds', icon: Bed, label: t('config_tab_beds') },
          { id: 'catalogs', icon: Database, label: t('config_tab_catalogs') },
          { id: 'data', icon: Server, label: t('config_tab_data') },
          { id: 'diagnostics', icon: Activity, label: t('config_tab_health') }
        ].map(tab => (
          <button 
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)} 
            className={`px-5 py-3 font-medium text-sm border-b-2 transition-all flex items-center gap-2 whitespace-nowrap 
              ${activeTab === tab.id 
                ? 'border-primary-600 text-primary-600 bg-primary-50/50 dark:bg-primary-900/20' 
                : 'border-transparent text-gray-500 dark:text-slate-400 hover:text-gray-700 dark:hover:text-slate-200 hover:bg-gray-50 dark:hover:bg-slate-700'}`}
          >
            <tab.icon size={18}/> {tab.label}
          </button>
        ))}
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-b-xl shadow-sm border border-t-0 border-gray-200 dark:border-slate-700 p-6 min-h-[400px] relative">
        {loading && <div className="absolute inset-0 z-10 bg-white/80 dark:bg-slate-800/80 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-primary-500" /></div>}

        {!loading && (
          <>
            {activeTab === 'general' && (
              <form onSubmit={handleSaveSettings} className="max-w-xl space-y-6 animate-in fade-in">
                <Input label={t('config_general_hospital_name')} value={settings.hospitalName} onChange={e => setSettings({...settings, hospitalName: e.target.value})} />
                <Input label={t('config_general_address')} value={settings.hospitalAddress} onChange={e => setSettings({...settings, hospitalAddress: e.target.value})} />
                <div className="pt-4 border-t dark:border-slate-700">
                  <Button type="submit" icon={Save}>{t('config_general_save_button')}</Button>
                </div>
              </form>
            )}

            {activeTab === 'users' && (
              <div className="animate-in fade-in">
                <div className="flex gap-2 mb-6">
                   <Button variant={userTabMode === 'accounts' ? 'primary' : 'outline'} onClick={() => setUserTabMode('accounts')} icon={Users}>{t('config_users_accounts_tab')}</Button>
                   <Button variant={userTabMode === 'roles' ? 'primary' : 'outline'} onClick={() => setUserTabMode('roles')} icon={Lock}>{t('config_users_roles_tab')}</Button>
                </div>

                {userTabMode === 'accounts' ? (
                  <>
                    <div className="flex justify-end mb-4"><Button icon={Plus} onClick={() => openUserModal()}>{t('config_users_add_button')}</Button></div>
                    <div className="overflow-x-auto border rounded-xl shadow-sm">
                      <table className="min-w-full divide-y">
                        <thead className="bg-slate-50 dark:bg-slate-900">
                          <tr>
                            <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_users_header_user')}</th>
                            <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_users_header_role')}</th>
                            <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase">{t('config_users_header_status')}</th>
                            <th className="px-4 py-3"></th>
                          </tr>
                        </thead>
                        <tbody className="bg-white divide-y dark:bg-slate-800">
                          {users.map(user => (
                            <tr key={user.id}>
                              <td className="px-4 py-3"><div className="font-medium">{user.fullName}</div><div className="text-xs text-slate-500">{user.username}</div></td>
                              <td className="px-4 py-3 capitalize"><Badge color="blue">{user.role}</Badge></td>
                              <td className="px-4 py-3 text-center"><Badge color={user.isActive ? 'green' : 'gray'}>{user.isActive ? 'Active' : 'Inactive'}</Badge></td>
                              <td className="px-4 py-3 text-right">
                                <button onClick={() => openUserModal(user)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                                <button onClick={() => handleDeleteUser(user.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </>
                ) : (
                  <div className="overflow-x-auto border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm">
                    <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                      <thead className="bg-slate-50 dark:bg-slate-900 sticky top-0 z-10">
                        <tr>
                          <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider w-1/4">
                            Feature
                          </th>
                          {availableRoles.map(role => (
                            <th key={role} className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase tracking-wider">
                              <div className="flex flex-col items-center gap-2">
                                <span className="capitalize">{role}</span>
                                {role !== 'admin' && (
                                  <Button size="sm" onClick={() => savePermissions(role)} className="!px-2 !py-0.5 !text-[10px] h-auto">
                                    {t('config_users_permissions_save_button')}
                                  </Button>
                                )}
                              </div>
                            </th>
                          ))}
                        </tr>
                      </thead>
                      <tbody className="bg-white dark:bg-slate-800">
                        {Object.entries(permissionGroups).map(([groupName, perms]) => (
                          <React.Fragment key={groupName}>
                            <tr className="bg-slate-50/50 dark:bg-slate-900/50">
                              <td colSpan={availableRoles.length + 1} className="px-4 py-2 text-sm font-bold text-slate-600 dark:text-slate-300">
                                {groupName}
                              </td>
                            </tr>
                            {perms.map(p => (
                              <tr key={p} className="hover:bg-slate-50 dark:hover:bg-slate-700/30">
                                <td className="px-4 py-3 text-sm font-medium text-slate-700 dark:text-slate-300 capitalize">
                                  {formatPermissionName(p)}
                                </td>
                                {availableRoles.map(role => (
                                  <td key={`${role}-${p}`} className="px-4 py-3 text-center">
                                    <input
                                      type="checkbox"
                                      className="h-5 w-5 rounded text-primary-600 focus:ring-primary-500 disabled:opacity-50 cursor-pointer disabled:cursor-not-allowed"
                                      checked={(rolePermissions[role] || []).includes(p)}
                                      onChange={() => togglePermission(role, p)}
                                      disabled={role === 'admin'}
                                    />
                                  </td>
                                ))}
                              </tr>
                            ))}
                          </React.Fragment>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'financial' && (
              <div className="animate-in fade-in">
                <div className="flex gap-2 mb-6">
                   <Button variant={financeTab === 'tax' ? 'primary' : 'outline'} onClick={() => setFinanceTab('tax')}>{t('config_financial_tax_tab')}</Button>
                   <Button variant={financeTab === 'payment' ? 'primary' : 'outline'} onClick={() => setFinanceTab('payment')}>{t('config_financial_payment_tab')}</Button>
                </div>
                {financeTab === 'tax' ? (
                  <div>
                    <div className="flex justify-end mb-4"><Button size="sm" icon={Plus} onClick={() => openFinanceModal('tax')}>{t('add')}</Button></div>
                    {taxes.map(t => <div key={t.id} className="flex justify-between items-center py-2 border-b last:border-0"><span>{t.name_en} ({t.rate}%)</span><div><button onClick={() => openFinanceModal('tax', t)} className="p-1"><Edit size={14}/></button><button onClick={() => handleDeleteFinance(t.id, 'tax')} className="p-1 text-red-500"><Trash2 size={14}/></button></div></div>)}
                  </div>
                ) : (
                  <div>
                    <div className="flex justify-end mb-4"><Button size="sm" icon={Plus} onClick={() => openFinanceModal('payment')}>{t('add')}</Button></div>
                    {paymentMethods.map(p => <div key={p.id} className="flex justify-between items-center py-2 border-b last:border-0"><span>{p.name_en}</span><div><button onClick={() => openFinanceModal('payment', p)} className="p-1"><Edit size={14}/></button><button onClick={() => handleDeleteFinance(p.id, 'payment')} className="p-1 text-red-500"><Trash2 size={14}/></button></div></div>)}
                  </div>
                )}
              </div>
            )}

            {activeTab === 'beds' && (
              <div className="animate-in fade-in">
                <div className="flex justify-end mb-4"><Button icon={Plus} onClick={() => openBedModal()}>{t('config_beds_add_button')}</Button></div>
                <div className="overflow-x-auto border rounded-xl shadow-sm">
                  <table className="min-w-full divide-y">
                    <thead className="bg-slate-50 dark:bg-slate-900">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_room')}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_type')}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_cost')}</th>
                        <th className="px-4 py-3 text-center text-xs font-bold text-gray-500 uppercase">{t('config_beds_header_status')}</th>
                        <th className="px-4 py-3"></th>
                      </tr>
                    </thead>
                    <tbody className="bg-white divide-y dark:bg-slate-800">
                      {beds.map(bed => (
                        <tr key={bed.id}>
                          <td className="px-4 py-3 font-medium">{bed.roomNumber}</td>
                          <td className="px-4 py-3">{bed.type}</td>
                          <td className="px-4 py-3 text-right font-mono">${bed.costPerDay}</td>
                          <td className="px-4 py-3 text-center capitalize"><Badge color={bed.status === 'available' ? 'green' : bed.status === 'cleaning' ? 'purple' : 'red'}>{bed.status}</Badge></td>
                          <td className="px-4 py-3 text-right">
                            <button onClick={() => openBedModal(bed)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                            <button onClick={() => handleDeleteBed(bed.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'catalogs' && (
              <div className="animate-in fade-in">
                <div className="flex flex-col sm:flex-row justify-between gap-4 mb-6">
                  <div className="flex gap-1 bg-gray-100 dark:bg-slate-900 p-1 rounded-xl w-full sm:w-auto overflow-x-auto">
                    {Object.keys(catalogMetadata).map(key => (
                      <button 
                        key={key}
                        onClick={() => setCatalogTab(key as CatalogType)} 
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all shadow-sm whitespace-nowrap ${catalogTab === key ? 'bg-white dark:bg-slate-800 text-primary-700 shadow' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}
                      >
                        {catalogMetadata[key as CatalogType].label}
                      </button>
                    ))}
                  </div>
                  <Button size="sm" icon={Plus} onClick={() => openItemModal()}>{t('config_catalogs_add_button')}</Button>
                </div>

                <div className="overflow-x-auto border rounded-xl shadow-sm">
                  <table className="min-w-full divide-y divide-gray-200 dark:divide-slate-700">
                    <thead className="bg-gray-50/80 dark:bg-slate-900">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_name_en')}</th>
                        <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_name_ar')}</th>
                        <th className="px-4 py-3 text-right text-xs font-bold text-gray-500 uppercase">{t('config_catalogs_header_details')}</th>
                        <th className="px-4 py-3 text-right"></th>
                      </tr>
                    </thead>
                    <tbody className="bg-white dark:bg-slate-800 divide-y divide-gray-200 dark:divide-slate-700">
                      {catalogMetadata[catalogTab].data.map((item: any) => (
                        <tr key={item.id} className="hover:bg-slate-50 dark:hover:bg-slate-700">
                          <td className="px-4 py-3 text-sm font-medium text-gray-900">{item.name_en}</td>
                          <td className="px-4 py-3 text-sm text-gray-700 dark:text-slate-300">{item.name_ar}</td>
                          <td className="px-4 py-3 text-sm text-right font-mono text-slate-500">
                            {item.cost !== undefined && `$${item.cost}`}
                            {item.base_cost !== undefined && `$${item.base_cost}`}
                            {item.rate !== undefined && `${item.rate}%`}
                            {item.related_role && <span className="mr-2 text-xs bg-gray-100 dark:bg-gray-700 px-1 rounded">{item.related_role}</span>}
                            {item.isActive !== undefined && <Badge color={item.isActive ? 'green' : 'gray'}>{item.isActive ? 'Active' : 'Inactive'}</Badge>}
                          </td>
                          <td className="px-4 py-3 text-right">
                            <button onClick={() => openItemModal(item)} className="p-1 text-slate-400 hover:text-primary-600"><Edit size={16}/></button>
                            <button onClick={() => handleDeleteItem(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16}/></button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {activeTab === 'data' && (
              <div className="max-w-xl space-y-8 animate-in fade-in">
                <Card title={t('config_data_backup_title')} action={<Button icon={Download} onClick={handleDownloadBackup}>{t('config_data_backup_button')}</Button>}>
                  <p>{t('config_data_backup_note')}</p>
                </Card>
                <Card title={t('config_data_restore_title')}>
                  <form onSubmit={handleRestoreDatabase} className="space-y-4">
                    <Input type="file" accept=".db,.sqlite,.sqlite3" onChange={e => setRestoreFile(e.target.files ? e.target.files[0] : null)} />
                    <Button type="submit" icon={Upload} disabled={!restoreFile}>{t('config_data_restore_button')}</Button>
                  </form>
                </Card>
                <Card title={t('config_data_danger_title')} className="border-red-500 bg-red-50 dark:bg-red-900/10">
                  <div className="flex justify-between items-center">
                    <div>
                      <h4 className="font-bold text-red-800 dark:text-red-300">{t('config_data_danger_reset_title')}</h4>
                      <p className="text-sm text-red-600 dark:text-red-400">{t('config_data_danger_reset_note')}</p>
                    </div>
                    <Button variant="danger" icon={RotateCcw} onClick={handleResetDatabase}>{t('config_data_danger_reset_button')}</Button>
                  </div>
                </Card>
              </div>
            )}

            {activeTab === 'diagnostics' && (
              <div className="max-w-3xl space-y-6 animate-in fade-in">
                <Button onClick={runDiagnostics} disabled={isTesting} icon={isTesting ? undefined : RefreshCw}>
                  {isTesting ? <><Loader2 className="w-4 h-4 mr-2 animate-spin"/>{t('config_health_running_button')}</> : t('config_health_run_button')}
                </Button>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                  <DiagnosticStat title={t('config_health_stat_status')} value={healthData?.status || 'Unknown'} icon={healthData?.status === 'operational' ? CheckCircle : AlertTriangle} />
                  <DiagnosticStat title={t('config_health_stat_latency')} value={healthData?.database?.latency || 'N/A'} icon={Database} />
                  <DiagnosticStat title={t('config_health_stat_uptime')} value={healthData?.uptime ? `${(healthData.uptime / 60).toFixed(1)} mins` : 'N/A'} icon={Activity} />
                  <DiagnosticStat title={t('config_health_stat_memory')} value={healthData?.memory?.rss || 'N/A'} icon={Server} />
                </div>

                {testLogs.length > 0 && (
                  <div className="bg-slate-900 text-slate-300 p-4 rounded-xl text-xs font-mono h-64 overflow-y-auto custom-scrollbar">
                    {testLogs.map((log, i) => <p key={i} className={`flex items-start gap-2 ${log.startsWith('❌') ? 'text-red-400' : log.startsWith('✅') ? 'text-green-400' : ''}`}><span className="text-slate-600 select-none">&gt;</span><span className="flex-1">{log}</span></p>)}
                  </div>
                )}
              </div>
            )}

          </>
        )}
      </div>

       {/* CATALOG ITEM MODAL (DYNAMIC) */}
      <Modal 
        isOpen={isItemModalOpen} 
        onClose={() => setIsItemModalOpen(false)} 
        title={`${editingItemId ? t('edit') : t('add')} ${catalogMetadata[catalogTab].label}`}
      >
        <form onSubmit={handleItemSubmit} className="space-y-4">
          {catalogMetadata[catalogTab].fields.map((field: any) => {
            if (field.type === 'textarea') {
              return <Textarea key={field.name} label={field.label} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})} required={field.required} />
            }
            if (field.type === 'select') {
                return (
                    <Select key={field.name} label={field.label} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})}>
                        <option value="">Select Role...</option>
                        {field.options.map((opt: string) => <option key={opt} value={opt}>{opt.charAt(0).toUpperCase() + opt.slice(1)}</option>)}
                    </Select>
                )
            }
            if (field.type === 'toggle') {
              return (
                <div key={field.name} className="flex items-center gap-2">
                  <input type="checkbox" id={field.name} checked={itemFormData[field.name] !== false} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.checked})} />
                  <label htmlFor={field.name}>{field.label}</label>
                </div>
              )
            }
            return <Input key={field.name} label={field.label} type={field.type || 'text'} value={itemFormData[field.name] || ''} onChange={e => setItemFormData({...itemFormData, [field.name]: e.target.value})} required={field.required} prefix={field.prefix} />
          })}
          <div className="flex justify-end pt-4 gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsItemModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit">{editingItemId ? t('edit') : t('add')}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title={editingUserId ? t('edit') : t('add')}>
        <form onSubmit={handleUserSubmit} className="space-y-4">
          <Input label={t('patients_modal_form_fullName')} required value={userForm.fullName || ''} onChange={e => setUserForm({...userForm, fullName: e.target.value})} />
          <Input label={t('settings_profile_username')} required value={userForm.username || ''} onChange={e => setUserForm({...userForm, username: e.target.value})} />
          <Input label={t('login_password_label')} type="password" placeholder={editingUserId ? 'Leave blank to keep unchanged' : ''} value={userForm.password || ''} onChange={e => setUserForm({...userForm, password: e.target.value})} required={!editingUserId} />
          <Input label={t('settings_profile_email')} type="email" value={userForm.email || ''} onChange={e => setUserForm({...userForm, email: e.target.value})} />
          <Select label={t('config_users_header_role')} value={userForm.role} onChange={e => setUserForm({...userForm, role: e.target.value})}>
            {availableRoles.map(r => <option key={r} value={r} className="capitalize">{r}</option>)}
          </Select>
          <div className="flex justify-end pt-4 gap-3">
            <Button type="button" variant="secondary" onClick={() => setIsUserModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit">{editingUserId ? t('edit') : t('add')}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={isBedModalOpen} onClose={() => setIsBedModalOpen(false)} title={editingBedId ? t('edit') : t('add')}>
         <form onSubmit={handleBedSubmit} className="space-y-4">
           <Input label={t('config_beds_header_room')} required value={bedForm.roomNumber || ''} onChange={e => setBedForm({...bedForm, roomNumber: e.target.value})} />
           <Select label={t('config_beds_header_type')} value={bedForm.type} onChange={e => setBedForm({...bedForm, type: e.target.value as any})}>
             <option>General</option><option>Private</option><option>ICU</option>
           </Select>
           <Input label={t('config_beds_header_cost')} type="number" value={bedForm.costPerDay || 0} onChange={e => setBedForm({...bedForm, costPerDay: parseFloat(e.target.value)})} />
           <Select label={t('status')} value={bedForm.status} onChange={e => setBedForm({...bedForm, status: e.target.value as any})}>
             <option value="available">Available</option>
             <option value="maintenance">Maintenance</option>
             <option value="cleaning">Cleaning</option>
             <option value="reserved">Reserved</option>
             <option value="occupied">Occupied</option>
           </Select>
           <div className="flex justify-end pt-4 gap-3">
             <Button type="button" variant="secondary" onClick={() => setIsBedModalOpen(false)}>{t('cancel')}</Button>
             <Button type="submit">{editingBedId ? t('edit') : t('add')}</Button>
           </div>
         </form>
      </Modal>

      <Modal isOpen={isFinanceModalOpen} onClose={() => setIsFinanceModalOpen(false)} title={`${editingFinanceId ? t('edit') : t('add')} ${financeTab === 'tax' ? t('config_financial_tax_tab') : t('config_financial_payment_tab')}`}>
        <form onSubmit={handleFinanceSubmit} className="space-y-4">
           <Input label="Name (EN)" required value={financeForm.name_en || ''} onChange={e => setFinanceForm({...financeForm, name_en: e.target.value})} />
           <Input label="Name (AR)" required value={financeForm.name_ar || ''} onChange={e => setFinanceForm({...financeForm, name_ar: e.target.value})} />
           {financeTab === 'tax' && (
             <Input label="Rate (%)" type="number" required value={financeForm.rate || ''} onChange={e => setFinanceForm({...financeForm, rate: e.target.value})} />
           )}
           <div className="flex items-center gap-2"><input type="checkbox" checked={financeForm.isActive !== false} onChange={e => setFinanceForm({...financeForm, isActive: e.target.checked})} /> Active</div>
           <div className="flex justify-end pt-2 gap-3">
             <Button type="button" variant="secondary" onClick={() => setIsFinanceModalOpen(false)}>{t('cancel')}</Button>
             <Button type="submit">{t('save')}</Button>
           </div>
        </form>
      </Modal>

      {/* --- CONFIRMATION DIALOG --- */}
      <ConfirmationDialog 
        isOpen={confirmState.isOpen}
        onClose={() => setConfirmState({ ...confirmState, isOpen: false })}
        onConfirm={() => {
          confirmState.action();
          setConfirmState({ ...confirmState, isOpen: false });
        }}
        title={confirmState.title}
        message={confirmState.message}
        type={confirmState.type || 'danger'}
      />
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Card, Button, Input, Select, Modal, Badge, Textarea, ConfirmationDialog } from '../components/UI';
import { 
  Plus, Search, Briefcase, Clock, 
  Calendar, DollarSign, Wallet,
  AlertTriangle, CheckCircle, User, Phone, Mail,
  Loader2, XCircle, Edit, Trash2, X, Check, MapPin
} from 'lucide-react';
import { api } from '../services/api';
import { MedicalStaff, Attendance, LeaveRequest, PayrollRecord, FinancialAdjustment } from '../types';
import { hasPermission, Permissions } from '../utils/rbac';
import { useTranslation } from '../context/TranslationContext';
import { useAuth } from '../context/AuthContext';

const DAYS_OF_WEEK_EN = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
const DAYS_OF_WEEK_AR = ['إث', 'ثل', 'أر', 'خم', 'جم', 'سب', 'أح'];

const roleDepartmentMap: Record<string, string[]> = {
  doctor: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology', 'Dermatology', 'Radiology', 'Anesthesiology', 'Internal Medicine'],
  nurse: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology'],
  technician: ['Radiology', 'Laboratory'],
  anesthesiologist: ['Anesthesiology', 'General Surgery'],
  pharmacist: ['Pharmacy'],
  hr_manager: ['Administration'],
  staff: ['Administration', 'Maintenance', 'Security', 'Support Services', 'Finance', 'IT Support'],
  medical_assistant: ['Cardiology', 'Neurology', 'Orthopedics', 'Pediatrics', 'Oncology', 'General Surgery', 'Emergency', 'Obstetrics and Gynecology', 'Dermatology', 'Internal Medicine']
};

export const Staff = () => {
  const { t, language } = useTranslation();
  const [activeTab, setActiveTab] = useState<'directory' | 'attendance' | 'leaves' | 'payroll' | 'financials'>('directory');
  const [staff, setStaff] = useState<MedicalStaff[]>([]);
  const { user: currentUser } = useAuth();
  const [loading, setLoading] = useState(true);

  const DAYS_OF_WEEK = language === 'ar' ? DAYS_OF_WEEK_AR : DAYS_OF_WEEK_EN;

  // Tab specific data
  const [attendance, setAttendance] = useState<Attendance[]>([]);
  const [leaves, setLeaves] = useState<LeaveRequest[]>([]);
  const [payroll, setPayroll] = useState<PayrollRecord[]>([]);
  const [financials, setFinancials] = useState<FinancialAdjustment[]>([]);

  // Catalogs for dropdowns
  const [departments, setDepartments] = useState<any[]>([]);
  const [specializations, setSpecializations] = useState<any[]>([]);
  const [banks, setBanks] = useState<any[]>([]);

  // UI States
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false); // Staff Add/Edit
  const [isAdjustmentModalOpen, setIsAdjustmentModalOpen] = useState(false); // Fine/Bonus/Loan
  const [isLeaveModalOpen, setIsLeaveModalOpen] = useState(false); // Request Leave
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]); // For attendance
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7)); // For payroll YYYY-MM

  // Advanced Process State
  const [processStatus, setProcessStatus] = useState<'idle' | 'processing' | 'success' | 'error'>('idle');
  const [processMessage, setProcessMessage] = useState('');

  // Confirm State
  const [confirmState, setConfirmState] = useState<{isOpen: boolean, title: string, message: string, action: () => void}>({ isOpen: false, title: '', message: '', action: () => {} });

  // Forms
  const [staffForm, setStaffForm] = useState<Partial<MedicalStaff & { bankName?: string, bankAccount?: string, address?: string } | any>>({});
  const [adjForm, setAdjForm] = useState({ staffId: '', type: 'bonus', amount: '', reason: '', date: new Date().toISOString().split('T')[0] });
  const [leaveForm, setLeaveForm] = useState({ staffId: '', type: 'sick', startDate: '', endDate: '', reason: '' });

  // New Attendance Modal State
  const [attendanceModal, setAttendanceModal] = useState<{
      isOpen: boolean;
      staffId: number;
      staffName: string;
      status: 'present' | 'late' | 'absent';
      checkIn: string;
  } | null>(null);

  const loadData = async (isBackground = false) => {
    if (!isBackground) setLoading(true);
    try {
      const [data, depts, specs, bankData] = await Promise.all([
        api.getStaff(),
        api.getDepartments(),
        api.getSpecializations(),
        api.getBanks()
      ]);
      setStaff(Array.isArray(data) ? data : []);
      setDepartments(Array.isArray(depts) ? depts : []);
      setSpecializations(Array.isArray(specs) ? specs : []);
      setBanks(Array.isArray(bankData) ? bankData : []);
    } catch (e) {
      console.error("Failed to load staff data:", e);
    } finally {
      if (!isBackground) setLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  useEffect(() => {
    const fetchTabData = async () => {
        if (activeTab === 'attendance') setAttendance(await api.getAttendance(selectedDate));
        else if (activeTab === 'leaves') setLeaves(await api.getLeaves());
        else if (activeTab === 'payroll') setPayroll(await api.getPayroll(selectedMonth));
        else if (activeTab === 'financials') setFinancials(await api.getFinancials('all'));
    };
    if(activeTab !== 'directory') fetchTabData();
  }, [activeTab, selectedDate, selectedMonth]);

  const canManageHR = hasPermission(currentUser, Permissions.MANAGE_HR);

  const handleCreateStaff = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!staffForm.fullName) return;

    setProcessStatus('processing');
    setProcessMessage(staffForm.id ? t('staff_updating') : t('staff_creating'));

    const { bankName, bankAccount, ...restOfForm } = staffForm;

    // Ensure numbers are converted, empty string becomes 0
    const payload = {
        ...restOfForm,
        baseSalary: parseFloat(restOfForm.baseSalary) || 0,
        consultationFee: parseFloat(restOfForm.consultationFee) || 0,
        consultationFeeFollowup: parseFloat(restOfForm.consultationFeeFollowup) || 0,
        consultationFeeEmergency: parseFloat(restOfForm.consultationFeeEmergency) || 0,
        bankDetails: { bankName, bankAccount }
    };

    try {
      if (payload.id) await api.updateStaff(payload.id, payload);
      else await api.addStaff(payload);

      setProcessStatus('success');
      setProcessMessage(staffForm.id ? t('staff_update_success') : t('staff_create_success'));

      await loadData(true);

      setTimeout(() => {
        setIsModalOpen(false);
        setProcessStatus('idle');
      }, 500);

    } catch (err: any) {
      setProcessStatus('error');
      setProcessMessage(err.response?.data?.error || t('staff_save_fail'));
    }
  };

  const openStaffModal = (s?: MedicalStaff) => {
      let bankDetailsParsed = { bankName: '', bankAccount: '' };
      if (s?.bankDetails) {
          if (typeof s.bankDetails === 'object' && s.bankDetails !== null) {
              bankDetailsParsed = { bankName: s.bankDetails.bankName, bankAccount: s.bankDetails.bankAccount };
          } else if (typeof s.bankDetails === 'string') {
              bankDetailsParsed = { bankName: s.bankDetails, bankAccount: '' };
          }
      }

      // Initialize number fields as strings (or empty strings if 0 for new)
      const formState = s ? { 
          ...s, 
          ...bankDetailsParsed,
          // If editing, keep existing values. If it was 0, it shows 0.
      } : { 
          fullName: '', type: 'doctor', status: 'active', 
          baseSalary: '', 
          availableDays: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'],
          availableTimeStart: '09:00', availableTimeEnd: '17:00',
          consultationFee: '', consultationFeeFollowup: '', consultationFeeEmergency: '',
          joinDate: new Date().toISOString().split('T')[0],
          address: '',
          ...bankDetailsParsed
      };

      setStaffForm(formState);
      setIsModalOpen(true);
  };

  const toggleDay = (day: string) => {
      const currentDays = staffForm.availableDays || [];
      const dayEN = DAYS_OF_WEEK_EN[DAYS_OF_WEEK.indexOf(day)];
      if (currentDays.includes(dayEN)) {
          setStaffForm({ ...staffForm, availableDays: currentDays.filter((d: string) => d !== dayEN) });
      } else {
          setStaffForm({ ...staffForm, availableDays: [...currentDays, dayEN] });
      }
  };

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newType = e.target.value;
    setStaffForm(prev => ({
        ...prev,
        type: newType as any,
        department: '',
        specialization: ''
    }));
  };

  const filteredDepartments = useMemo(() => {
    if (!staffForm.type) return departments;
    const allowedDepts = roleDepartmentMap[staffForm.type];
    if (!allowedDepts || allowedDepts.length === 0) return departments;
    return departments.filter(d => allowedDepts.includes(d.name_en));
  }, [staffForm.type, departments]);

  const filteredSpecializations = useMemo(() => {
    if (!staffForm.type) return specializations;
    // Filter by related_role. If related_role is null or matches current type.
    return specializations.filter(s => !s.related_role || s.related_role === staffForm.type);
  }, [staffForm.type, specializations]);

  const openAttendanceModal = (staffId: number, staffName: string, status: 'present' | 'late' | 'absent') => {
      const existingRecord = attendance.find(a => a.staffId === staffId);
      const now = new Date();
      const timeString = now.toTimeString().slice(0, 5);

      setAttendanceModal({
          isOpen: true,
          staffId,
          staffName,
          status,
          checkIn: existingRecord?.checkIn || timeString
      });
  };

  const handleAttendanceSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!attendanceModal) return;

      setProcessStatus('processing');
      setProcessMessage(t('processing'));

      try {
          await api.markAttendance({
              staffId: attendanceModal.staffId, 
              date: selectedDate, 
              status: attendanceModal.status,
              checkIn: ['present', 'late'].includes(attendanceModal.status) ? attendanceModal.checkIn : null
          });
          const data = await api.getAttendance(selectedDate);
          setAttendance(data);

          setProcessStatus('success');
          setTimeout(() => {
              setProcessStatus('idle');
              setAttendanceModal(null);
          }, 500);
      } catch (err: any) {
          setProcessStatus('error');
          setProcessMessage(err.message || 'Failed to mark attendance');
      }
  };

  const handleLeaveRequest = async (e: React.FormEvent) => {
      e.preventDefault();
      await api.requestLeave(leaveForm);
      setIsLeaveModalOpen(false);
      const data = await api.getLeaves();
      setLeaves(data);
  };

  const updateLeaveStatus = async (id: number, status: string) => {
      await api.updateLeaveStatus(id, status);
      const data = await api.getLeaves();
      setLeaves(data);
  };

  const handleGeneratePayroll = () => {
      setConfirmState({
          isOpen: true,
          title: t('staff_tab_payroll'),
          message: t('staff_generate_payroll_confirm', {month: selectedMonth}),
          action: async () => {
              await api.generatePayroll({ month: selectedMonth });
              const data = await api.getPayroll(selectedMonth);
              setPayroll(data);
          }
      });
  };

  const handleAdjustmentSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      await api.addAdjustment({ ...adjForm, amount: parseFloat(adjForm.amount) });
      setIsAdjustmentModalOpen(false);
      const data = await api.getFinancials('all');
      setFinancials(data);
  };

  const statusOrder: { [key in MedicalStaff['status']]: number } = {
    active: 1,
    inactive: 2,
    dismissed: 3,
  };

  const sortedStaff = staff
    .filter(s => s.fullName.toLowerCase().includes(searchTerm.toLowerCase()))
    .sort((a, b) => (statusOrder[a.status] || 99) - (statusOrder[b.status] || 99));

  return (
    <div className="space-y-6">
      {/* Loading & Status Overlay */}
      {processStatus !== 'idle' && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-2xl flex flex-col items-center max-w-sm w-full mx-4 relative overflow-hidden text-center transform scale-100 animate-in zoom-in-95 border dark:border-slate-700">
            {processStatus === 'processing' && (
              <>
                <div className="relative mb-6">
                   <div className="w-16 h-16 border-4 border-slate-100 dark:border-slate-800 border-t-primary-600 rounded-full animate-spin"></div>
                   <Loader2 className="absolute inset-0 m-auto text-primary-600 animate-pulse" size={24}/>
                </div>
                <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">{t('processing')}</h3>
                <p className="text-slate-500 dark:text-slate-400">{processMessage}</p>
              </>
            )}
            {processStatus === 'success' && (
              <>
                <div className="w-20 h-20 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mb-6 text-green-600 dark:text-green-400 animate-in zoom-in duration-300">
                  <CheckCircle size={40} strokeWidth={3} />
                </div>
                <h3 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">{t('success')}</h3>
                <p className="text-slate-600 dark:text-slate-300 font-medium">{processMessage}</p>
              </>
            )}
            {processStatus === 'error' && (
              <>
                <div className="w-20 h-20 bg-red-100 dark:bg-red-900/30 rounded-full flex items-center justify-center mb-6 text-red-600 dark:text-red-400 animate-in zoom-in duration-300">
                  <XCircle size={40} strokeWidth={3} />
                </div>
                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">{t('patients_process_title_failed')}</h3>
                <p className="text-red-600 bg-red-50 dark:bg-red-900/20 p-3 rounded-xl border border-red-100 dark:border-red-900/50 text-sm mb-6 w-full">{processMessage}</p>
                <Button variant="secondary" onClick={() => setProcessStatus('idle')} className="w-full">{t('close')}</Button>
              </>
            )}
          </div>
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 dark:text-white">{t('staff_title')}</h1>
          <p className="text-sm text-slate-500 dark:text-slate-400">{t('staff_subtitle')}</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-x-auto">
          {[
              { id: 'directory', label: t('staff_tab_directory'), icon: Briefcase },
              { id: 'attendance', label: t('staff_tab_attendance'), icon: Clock },
              { id: 'leaves', label: t('staff_tab_leaves'), icon: Calendar },
              { id: 'payroll', label: t('staff_tab_payroll'), icon: DollarSign },
              { id: 'financials', label: t('staff_tab_financials'), icon: Wallet },
          ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-primary-50 dark:bg-primary-900/20 text-primary-700 dark:text-primary-300 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
              >
                  <tab.icon size={16} /> {tab.label}
              </button>
          ))}
      </div>

      {/* --- DIRECTORY TAB --- */}
      {activeTab === 'directory' && (
          <div className="animate-in fade-in">
              <div className="flex justify-between mb-4">
                  <div className="relative w-72">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                      <input 
                        type="text" 
                        placeholder={t('staff_search_placeholder')} 
                        className="pl-9 pr-4 py-2 w-full rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-primary-500"
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                      />
                  </div>
                  {canManageHR && <Button onClick={() => openStaffModal()} icon={Plus}>{t('staff_add_employee_button')}</Button>}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                  {sortedStaff.map(person => (
                      <div key={person.id} className="bg-white dark:bg-slate-800 p-5 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm hover:shadow-md transition-all group">
                          <div className="flex justify-between items-start mb-4">
                              <div className="flex items-center gap-3">
                                  <div className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-lg text-white bg-gradient-to-br from-slate-400 to-slate-500`}>
                                      {person.fullName.charAt(0)}
                                  </div>
                                  <div>
                                      <h3 className="font-bold text-slate-800 dark:text-white line-clamp-1">{person.fullName}</h3>
                                      <Badge color="blue">{person.type}</Badge>
                                  </div>
                              </div>
                              <div className={`w-2 h-2 rounded-full ${person.status === 'active' ? 'bg-green-500' : 'bg-gray-300'}`}></div>
                          </div>

                          <div className="space-y-2 text-sm text-slate-500 dark:text-slate-400 mb-4">
                              <div className="flex items-center gap-2"><Briefcase size={14}/> {person.department || 'N/A'}</div>
                              <div className="flex items-center gap-2"><Phone size={14}/> {person.phone || 'N/A'}</div>
                              <div className="flex items-center gap-2 truncate"><Mail size={14}/> {person.email || 'N/A'}</div>
                          </div>

                          {canManageHR && (
                              <Button variant="outline" className="w-full" onClick={() => openStaffModal(person)}>
                                  {t('edit')}
                              </Button>
                          )}
                      </div>
                  ))}
              </div>
          </div>
      )}

      {/* --- ATTENDANCE TAB --- */}
      {activeTab === 'attendance' && (
          <div className="animate-in fade-in">
              <div className="flex justify-end mb-4">
                  <Input type="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)} className="w-auto" />
              </div>
              <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                  <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 font-medium">
                          <tr>
                              <th className="px-4 py-3">{t('staff_form_role_title')}</th>
                              <th className="px-4 py-3">Status</th>
                              <th className="px-4 py-3">Check In</th>
                              <th className="px-4 py-3">Check Out</th>
                              {canManageHR && <th className="px-4 py-3 text-right">{t('actions')}</th>}
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                          {staff.filter(s => s.status === 'active').map(s => {
                              const record = attendance.find(a => a.staffId === s.id);
                              return (
                                  <tr key={s.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50">
                                      <td className="px-4 py-3 font-medium text-slate-900 dark:text-white">{s.fullName} <span className="text-xs text-slate-400 block">{s.type}</span></td>
                                      <td className="px-4 py-3">
                                          <Badge color={record?.status === 'present' ? 'green' : record?.status === 'absent' ? 'red' : record?.status === 'late' ? 'orange' : 'gray'}>
                                              {record?.status || 'Pending'}
                                          </Badge>
                                      </td>
                                      <td className="px-4 py-3">{record?.checkIn || '-'}</td>
                                      <td className="px-4 py-3">{record?.checkOut || '-'}</td>
                                      {canManageHR && (
                                          <td className="px-4 py-3 text-right">
                                              <div className="flex justify-end gap-1">
                                                  <button onClick={() => openAttendanceModal(s.id, s.fullName, 'present')} className="p-1.5 text-green-600 hover:bg-green-50 rounded" title="Present"><CheckCircle size={16}/></button>
                                                  <button onClick={() => openAttendanceModal(s.id, s.fullName, 'late')} className="p-1.5 text-orange-600 hover:bg-orange-50 rounded" title="Late"><Clock size={16}/></button>
                                                  <button onClick={() => openAttendanceModal(s.id, s.fullName, 'absent')} className="p-1.5 text-red-600 hover:bg-red-50 rounded" title="Absent"><XCircle size={16}/></button>
                                              </div>
                                          </td>
                                      )}
                                  </tr>
                              )
                          })}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

      {/* --- LEAVES TAB --- */}
      {activeTab === 'leaves' && (
          <div className="animate-in fade-in">
              <div className="flex justify-end mb-4">
                  <Button icon={Plus} onClick={() => setIsLeaveModalOpen(true)}>{t('staff_modal_leave_title')}</Button>
              </div>
              <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                  <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 font-medium">
                          <tr>
                              <th className="px-4 py-3">Staff</th>
                              <th className="px-4 py-3">Type</th>
                              <th className="px-4 py-3">Dates</th>
                              <th className="px-4 py-3">Reason</th>
                              <th className="px-4 py-3">Status</th>
                              {canManageHR && <th className="px-4 py-3 text-right">Actions</th>}
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                          {leaves.length === 0 ? <tr><td colSpan={6} className="text-center py-8 text-slate-400">{t('no_data')}</td></tr> : leaves.map(leave => (
                              <tr key={leave.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50">
                                  <td className="px-4 py-3 font-medium">{leave.staffName}</td>
                                  <td className="px-4 py-3 capitalize">{leave.type}</td>
                                  <td className="px-4 py-3 text-slate-500">{new Date(leave.startDate).toLocaleDateString()} - {new Date(leave.endDate).toLocaleDateString()}</td>
                                  <td className="px-4 py-3 text-slate-500 truncate max-w-xs">{leave.reason}</td>
                                  <td className="px-4 py-3"><Badge color={leave.status === 'approved' ? 'green' : leave.status === 'rejected' ? 'red' : 'yellow'}>{leave.status}</Badge></td>
                                  {canManageHR && leave.status === 'pending' && (
                                      <td className="px-4 py-3 text-right space-x-2">
                                          <button onClick={() => updateLeaveStatus(leave.id, 'approved')} className="text-green-600 hover:underline">Approve</button>
                                          <button onClick={() => updateLeaveStatus(leave.id, 'rejected')} className="text-red-600 hover:underline">Reject</button>
                                      </td>
                                  )}
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

      {/* --- PAYROLL TAB --- */}
      {activeTab === 'payroll' && (
          <div className="animate-in fade-in">
              <div className="flex justify-between items-center mb-4">
                  <Input type="month" value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-auto" />
                  {canManageHR && <Button icon={DollarSign} onClick={handleGeneratePayroll}>Generate Payroll</Button>}
              </div>
              <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                  <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 font-medium">
                          <tr>
                              <th className="px-4 py-3">Staff</th>
                              <th className="px-4 py-3 text-right">Base Salary</th>
                              <th className="px-4 py-3 text-right">Bonuses</th>
                              <th className="px-4 py-3 text-right">Fines/Loans</th>
                              <th className="px-4 py-3 text-right font-bold">Net Salary</th>
                              <th className="px-4 py-3 text-center">Status</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                          {payroll.length === 0 ? <tr><td colSpan={6} className="text-center py-8 text-slate-400">{t('no_data')}</td></tr> : payroll.map(p => (
                              <tr key={p.id}>
                                  <td className="px-4 py-3 font-medium">{p.staffName}</td>
                                  <td className="px-4 py-3 text-right">${p.baseSalary.toLocaleString()}</td>
                                  <td className="px-4 py-3 text-right text-green-600">+${p.totalBonuses.toLocaleString()}</td>
                                  <td className="px-4 py-3 text-right text-red-600">-${p.totalFines.toLocaleString()}</td>
                                  <td className="px-4 py-3 text-right font-bold text-slate-900 dark:text-white">${p.netSalary.toLocaleString()}</td>
                                  <td className="px-4 py-3 text-center"><Badge color={p.status === 'paid' ? 'green' : 'yellow'}>{p.status}</Badge></td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

      {/* --- FINANCIALS TAB --- */}
      {activeTab === 'financials' && (
          <div className="animate-in fade-in">
              <div className="flex justify-end mb-4">
                  <Button icon={Plus} onClick={() => setIsAdjustmentModalOpen(true)}>Add Entry</Button>
              </div>
              <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                  <table className="w-full text-sm text-left">
                      <thead className="bg-slate-50 dark:bg-slate-900 text-slate-500 font-medium">
                          <tr>
                              <th className="px-4 py-3">Date</th>
                              <th className="px-4 py-3">Staff</th>
                              <th className="px-4 py-3">Type</th>
                              <th className="px-4 py-3">Amount</th>
                              <th className="px-4 py-3">Reason</th>
                          </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                          {financials.length === 0 ? <tr><td colSpan={5} className="text-center py-8 text-slate-400">{t('no_data')}</td></tr> : financials.map(f => (
                              <tr key={f.id}>
                                  <td className="px-4 py-3 text-slate-500">{new Date(f.date).toLocaleDateString()}</td>
                                  <td className="px-4 py-3 font-medium">{f.staffName}</td>
                                  <td className="px-4 py-3 capitalize"><Badge color={f.type === 'bonus' ? 'green' : f.type === 'fine' ? 'red' : 'orange'}>{f.type}</Badge></td>
                                  <td className="px-4 py-3 font-mono">${f.amount}</td>
                                  <td className="px-4 py-3 text-slate-500">{f.reason}</td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

      {/* --- MODALS --- */}

      {/* Attendance Modal (New) */}
      {attendanceModal && (
          <Modal isOpen={attendanceModal.isOpen} onClose={() => setAttendanceModal(null)} title={t('staff_attendance_modal_title')}>
              <form onSubmit={handleAttendanceSubmit} className="space-y-4">
                  <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-200 dark:border-slate-700 mb-4">
                      <div className="flex justify-between items-center mb-2">
                          <span className="text-sm text-slate-500">{t('staff_form_role_title')}</span>
                          <span className="font-bold text-slate-900 dark:text-white">{attendanceModal.staffName}</span>
                      </div>
                      <div className="flex justify-between items-center">
                          <span className="text-sm text-slate-500">{t('date')}</span>
                          <span className="font-bold text-slate-900 dark:text-white">{selectedDate}</span>
                      </div>
                  </div>

                  <div className="space-y-2">
                      <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300">{t('staff_attendance_mark_as')}</label>
                      <div className="flex gap-4">
                          <Badge 
                              color={attendanceModal.status === 'present' ? 'green' : attendanceModal.status === 'late' ? 'orange' : 'red'} 
                              className="text-lg px-4 py-2 capitalize"
                          >
                              {attendanceModal.status}
                          </Badge>
                      </div>
                  </div>

                  {['present', 'late'].includes(attendanceModal.status) && (
                      <Input 
                          type="time" 
                          label={t('staff_attendance_time')} 
                          required 
                          value={attendanceModal.checkIn} 
                          onChange={e => setAttendanceModal({...attendanceModal, checkIn: e.target.value})} 
                      />
                  )}

                  {attendanceModal.status === 'absent' && (
                      <p className="text-sm text-slate-500 italic">
                          Staff member will be marked as absent for the selected date.
                      </p>
                  )}

                  <div className="flex justify-end pt-4 gap-3 border-t dark:border-slate-700 mt-6">
                      <Button type="button" variant="secondary" onClick={() => setAttendanceModal(null)}>{t('cancel')}</Button>
                      <Button type="submit">{t('staff_attendance_confirm')}</Button>
                  </div>
              </form>
          </Modal>
      )}

      {/* Staff Add/Edit Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={staffForm.id ? t('staff_modal_edit_title') : t('staff_modal_add_title')}>
          <form onSubmit={handleCreateStaff} className="space-y-4">
              <div className="space-y-4">
                  <h4 className="text-xs font-bold text-slate-400 uppercase">{t('staff_form_personal_title')}</h4>
                  <Input label={t('patients_modal_form_fullName')} required value={staffForm.fullName || ''} onChange={e => setStaffForm({...staffForm, fullName: e.target.value})} />
                  <div className="grid grid-cols-2 gap-4">
                      <Input label={t('settings_profile_email')} type="email" value={staffForm.email || ''} onChange={e => setStaffForm({...staffForm, email: e.target.value})} />
                      <Input label={t('settings_profile_phone')} value={staffForm.phone || ''} onChange={e => setStaffForm({...staffForm, phone: e.target.value})} />
                  </div>
                  <Input label={t('patients_modal_form_address')} value={staffForm.address || ''} onChange={e => setStaffForm({...staffForm, address: e.target.value})} />
              </div>

              <div className="space-y-4">
                  <h4 className="text-xs font-bold text-slate-400 uppercase">{t('staff_form_role_title')}</h4>
                  <div className="grid grid-cols-2 gap-4">
                      <Select label="Role" value={staffForm.type} onChange={handleTypeChange}>
                          {Object.keys(roleDepartmentMap).map(role => <option key={role} value={role} className="capitalize">{role.replace('_', ' ')}</option>)}
                      </Select>
                      <Select label={t('status')} value={staffForm.status} onChange={e => setStaffForm({...staffForm, status: e.target.value as any})}>
                          <option value="active">Active</option>
                          <option value="inactive">Inactive</option>
                          <option value="dismissed">Dismissed</option>
                      </Select>
                  </div>
                  <Select label={t('staff_select_department')} value={staffForm.department || ''} onChange={e => setStaffForm({...staffForm, department: e.target.value})}>
                      <option value="">{t('staff_select_department')}</option>
                      {filteredDepartments.map(d => <option key={d.id} value={d.name_en}>{language === 'ar' ? d.name_ar : d.name_en}</option>)}
                  </Select>

                  {filteredSpecializations.length > 0 && (
                    <Select label={t('staff_select_specialization')} value={staffForm.specialization || ''} onChange={e => setStaffForm({...staffForm, specialization: e.target.value})}>
                        <option value="">{t('staff_select_specialization')}</option>
                        {filteredSpecializations.map(s => <option key={s.id} value={s.name_en}>{language === 'ar' ? s.name_ar : s.name_en}</option>)}
                    </Select>
                  )}
              </div>

              <div className="space-y-4">
                  <h4 className="text-xs font-bold text-slate-400 uppercase">{t('staff_form_schedule_title')}</h4>
                  <div className="flex flex-wrap gap-2">
                      {DAYS_OF_WEEK.map((day, i) => (
                          <button 
                              key={day} 
                              type="button"
                              onClick={() => toggleDay(day)}
                              className={`px-3 py-1 text-xs font-bold rounded-lg border transition-all ${(staffForm.availableDays || []).includes(DAYS_OF_WEEK_EN[i]) ? 'bg-primary-600 text-white border-primary-600' : 'bg-white dark:bg-slate-800 text-slate-500 border-slate-200 dark:border-slate-700'}`}
                          >
                              {day}
                          </button>
                      ))}
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                      <Input type="time" label="Start Time" value={staffForm.availableTimeStart || ''} onChange={e => setStaffForm({...staffForm, availableTimeStart: e.target.value})} />
                      <Input type="time" label="End Time" value={staffForm.availableTimeEnd || ''} onChange={e => setStaffForm({...staffForm, availableTimeEnd: e.target.value})} />
                  </div>
              </div>

              <div className="space-y-4">
                  <h4 className="text-xs font-bold text-slate-400 uppercase">{t('staff_form_financial_title')}</h4>
                  <Input type="number" label={t('staff_form_salary')} value={staffForm.baseSalary} onChange={e => setStaffForm({...staffForm, baseSalary: e.target.value})} />
                  <div className="grid grid-cols-3 gap-3">
                      <Input type="number" label={t('staff_form_consultation_fee')} value={staffForm.consultationFee} onChange={e => setStaffForm({...staffForm, consultationFee: e.target.value})} />
                      <Input type="number" label={t('staff_form_followup_fee')} value={staffForm.consultationFeeFollowup} onChange={e => setStaffForm({...staffForm, consultationFeeFollowup: e.target.value})} />
                      <Input type="number" label={t('staff_form_emergency_fee')} value={staffForm.consultationFeeEmergency} onChange={e => setStaffForm({...staffForm, consultationFeeEmergency: e.target.value})} />
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                      <Select label={t('staff_form_bank_name')} value={staffForm.bankName || ''} onChange={e => setStaffForm({...staffForm, bankName: e.target.value})}>
                          <option value="">Select Bank...</option>
                          {banks.map(bank => <option key={bank.id} value={bank.name_en}>{language === 'ar' ? bank.name_ar : bank.name_en}</option>)}
                      </Select>
                      <Input label={t('staff_form_bank_account')} value={staffForm.bankAccount || ''} onChange={e => setStaffForm({...staffForm, bankAccount: e.target.value})} />
                  </div>
                  <Input type="date" label={t('staff_join_date')} value={staffForm.joinDate || ''} onChange={e => setStaffForm({...staffForm, joinDate: e.target.value})} />
              </div>

              <div className="flex justify-end pt-4 gap-3 border-t dark:border-slate-700">
                  <Button type="button" variant="secondary" onClick={() => setIsModalOpen(false)}>{t('cancel')}</Button>
                  <Button type="submit">{t('save')}</Button>
              </div>
          </form>
      </Modal>

      {/* Leave Request Modal */}
      <Modal isOpen={isLeaveModalOpen} onClose={() => setIsLeaveModalOpen(false)} title={t('staff_modal_leave_title')}>
          <form onSubmit={handleLeaveRequest} className="space-y-4">
              <Select label="Staff Member" required value={leaveForm.staffId} onChange={e => setLeaveForm({...leaveForm, staffId: e.target.value})}>
                  <option value="">Select Staff...</option>
                  {staff.filter(s => s.status === 'active').map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}
              </Select>
              <Select label="Leave Type" value={leaveForm.type} onChange={e => setLeaveForm({...leaveForm, type: e.target.value})}>
                  <option value="sick">Sick Leave</option>
                  <option value="vacation">Vacation</option>
                  <option value="casual">Casual</option>
                  <option value="unpaid">Unpaid</option>
              </Select>
              <div className="grid grid-cols-2 gap-4">
                  <Input type="date" label="Start Date" required value={leaveForm.startDate} onChange={e => setLeaveForm({...leaveForm, startDate: e.target.value})} />
                  <Input type="date" label="End Date" required value={leaveForm.endDate} onChange={e => setLeaveForm({...leaveForm, endDate: e.target.value})} />
              </div>
              <Textarea label="Reason" rows={2} value={leaveForm.reason} onChange={e => setLeaveForm({...leaveForm, reason: e.target.value})} />
              <div className="flex justify-end pt-4 gap-3">
                  <Button type="button" variant="secondary" onClick={() => setIsLeaveModalOpen(false)}>{t('cancel')}</Button>
                  <Button type="submit">{t('submit')}</Button>
              </div>
          </form>
      </Modal>

      {/* Financial Adjustment Modal */}
      <Modal isOpen={isAdjustmentModalOpen} onClose={() => setIsAdjustmentModalOpen(false)} title="Financial Adjustment">
          <form onSubmit={handleAdjustmentSubmit} className="space-y-4">
              <Select label="Staff Member" required value={adjForm.staffId} onChange={e => setAdjForm({...adjForm, staffId: e.target.value})}>
                  <option value="">Select Staff...</option>
                  {staff.filter(s => s.status === 'active').map(s => <option key={s.id} value={s.id}>{s.fullName}</option>)}
              </Select>
              <Select label="Type" value={adjForm.type} onChange={e => setAdjForm({...adjForm, type: e.target.value})}>
                  <option value="bonus">Bonus</option>
                  <option value="fine">Fine</option>
                  <option value="loan">Loan</option>
              </Select>
              <Input type="number" label="Amount ($)" required value={adjForm.amount} onChange={e => setAdjForm({...adjForm, amount: e.target.value})} />
              <Input type="date" label="Date" required value={adjForm.date} onChange={e => setAdjForm({...adjForm, date: e.target.value})} />
              <Textarea label="Reason" rows={2} value={adjForm.reason} onChange={e => setAdjForm({...adjForm, reason: e.target.value})} />
              <div className="flex justify-end pt-4 gap-3">
                  <Button type="button" variant="secondary" onClick={() => setIsAdjustmentModalOpen(false)}>{t('cancel')}</Button>
                  <Button type="submit">{t('submit')}</Button>
              </div>
          </form>
      </Modal>

      {/* Confirmation Dialog */}
      <ConfirmationDialog 
        isOpen={confirmState.isOpen}
        onClose={() => setConfirmState({ ...confirmState, isOpen: false })}
        onConfirm={confirmState.action}
        title={confirmState.title}
        message={confirmState.message}
      />
    </div>
  );
};
